er" ), Round(batnum), GetFormattedTime(timetoattack)) AddDescLine(lines, s, "batted" ) end end if quaker then local nextquake = quaker.nextquake if IsPosNumber(nextquake) then local s = string.format(GetString( "quaketimer" ), GetFormattedTime(nextquake)) AddDescLine(lines, s, "quaker" ) end end if volcanomanager then local segs = IsFunction(volcanomanager.GetNumSegmentsUntilEruption) and volcanomanager:GetNumSegmentsUntilEruption() local segtime = IsNonNegNumber(TUNING.SEG_TIME) and TUNING.SEG_TIME local daytime = IsNonNegNumber(TUNING.TOTAL_DAY_TIME) and TUNING.TOTAL_DAY_TIME if IsNonNegNumber(segs) and segtime and daytime then local timeleftinseg = math.floor(daytime * GetClock():GetNormTime() / segtime) * segtime timeleftinseg = daytime * GetClock():GetNormTime() - timeleftinseg local timeleft = segs * segtime - timeleftinseg local s = string.format(GetString( "volcanotimer" ), GetFormattedTime(timeleft)) AddDescLine(lines, s, "volcanomanager" ) end end if basehassler then local hasslers = basehassler.hasslers if IsTable(hasslers) and next(hasslers) then for k, hassler in pairs(hasslers) do local nameStr = GetNameString(hassler.prefab) or "" local state = IsFunction(basehassler.GetHasslerState) and basehassler:GetHasslerState(k) local stateStr = IsNonEmptyString(state) and (state == "WAITING" or state == "WARNING" ) and "("..GetString( "timer_"..state)..")" or "" local timer = hassler.timer if IsNonEmptyString(nameStr) and IsNonEmptyString(stateStr) then local s = nameStr..stateStr..(IsNumber(timer) and ":"..GetFormattedTime(timer) or "" ) AddDescLine(lines, s, "basehassler" ) end end end end if tigersharker then local timeleft1 = IsFunction(tigersharker.TimeUntilRespawn) and tigersharker:TimeUntilRespawn() timeleft1 = IsPosNumber(timeleft1) and timeleft1 or 0x0 local timeleft2 = IsFunction(tigersharker.TimeUntilCanAppear) and tigersharker:TimeUntilCanAppear() timeleft2 = IsPosNumber(timeleft2) and timeleft2 or 0x0 local timeleft = math.max(timeleft1, timeleft2) local canSpawn = IsFunction(tigersharker.CanSpawn) and tigersharker:CanSpawn() local nameStr = GetNameString( "tigershark" ) or "" if IsNonEmptyString(nameStr) and (canSpawn or timeleft > 0x0) then local s = nameStr..(canSpawn and ":"..GetString( "timer_ready" ) or ":"..GetFormattedTime(timeleft)) AddDescLine(lines, s, "tigersharker" ) end end if krakener then local timeleft = IsFunction(krakener.TimeUntilCanSpawn) and krakener:TimeUntilCanSpawn() timeleft = IsPosNumber(timeleft) and timeleft or 0x0 local canSpawn = IsFunction(krakener.CanSpawn) and krakener:CanSpawn() local nameStr = GetNameString( "kraken" ) or "" if IsNonEmptyString(nameStr) and (canSpawn or timeleft > 0x0) then local s = nameStr..(canSpawn and ":"..GetString( "timer_ready" ) or ":"..GetFormattedTime(timeleft)) AddDescLine(lines, s, "krakener" ) end end if rocmanager then local spawntime = rocmanager.dycSpawnTime local timeleft = IsNumber(spawntime) and spawntime - GetTime() or 0x0 local disabled = rocmanager.disabled local nameStr = STRINGS.UI.CUSTOMIZATIONSCREEN.NAMES.ROC or "" if IsNonEmptyString(nameStr) and not disabled and timeleft > 0x0 then local s = nameStr..":"..GetFormattedTime(timeleft) AddDescLine(lines, s, "rocmanager" ) end end return lines end return DYCGetDescLines 